import{_ as a,c as i,o as l,a1 as r}from"./chunks/framework.DILC4Csi.js";const c=JSON.parse('{"title":"進階：流水線與內部機制 | AI App Factory 教程","description":"深入了解 AI App Factory 的 7 階段流水線、Sisyphus 調度器、權限安全機制和失敗處理策略。掌握上下文優化與高級配置技巧。","frontmatter":{"title":"進階：流水線與內部機制 | AI App Factory 教程","sidebarTitle":"進階：流水線","subtitle":"進階：流水線與內部機制","description":"深入了解 AI App Factory 的 7 階段流水線、Sisyphus 調度器、權限安全機制和失敗處理策略。掌握上下文優化與高級配置技巧。","tags":["流水線","調度器","權限安全","失敗處理"],"prerequisite":["start-pipeline-overview"],"order":80},"headers":[],"relativePath":"zh-tw/hyz1992/agent-app-factory/advanced/index.md","filePath":"zh-tw/hyz1992/agent-app-factory/advanced/index.md"}'),e={name:"zh-tw/hyz1992/agent-app-factory/advanced/index.md"};function o(s,t,n,p,d,h){return l(),i("div",null,[...t[0]||(t[0]=[r('<h1 id="進階-流水線與內部機制" tabindex="-1">進階：流水線與內部機制 <a class="header-anchor" href="#進階-流水線與內部機制" aria-label="Permalink to &quot;進階：流水線與內部機制&quot;">​</a></h1><p>本章節深入講解 AI App Factory 的核心機制和高級功能，包括 7 階段流水線的詳細工作原理、Sisyphus 調度器的調度策略、權限與安全機制、失敗處理策略，以及如何通過上下文優化節省 Token 成本。</p><div class="warning custom-block"><p class="custom-block-title">前置條件</p><p>學習本章節前，請確保已完成：</p><ul><li><a href="./../../start/getting-started/">快速開始</a> 和 <a href="./../../start/installation/">安裝配置</a></li><li><a href="./../../start/pipeline-overview/">7 階段流水線概覽</a></li><li><a href="./../../platforms/claude-code/">平台整合</a> 配置</li></ul></div><h2 id="章節內容" tabindex="-1">章節內容 <a class="header-anchor" href="#章節內容" aria-label="Permalink to &quot;章節內容&quot;">​</a></h2><p>本章節包含以下主題：</p><h3 id="_7-階段流水線詳解" tabindex="-1">7 階段流水線詳解 <a class="header-anchor" href="#_7-階段流水線詳解" aria-label="Permalink to &quot;7 階段流水線詳解&quot;">​</a></h3><ul><li><p><strong><a href="./stage-bootstrap/">階段 1：Bootstrap - 結構化產品想法</a></strong></p><ul><li>學習如何將模糊的產品想法轉化為結構化文件</li><li>理解 Bootstrap Agent 的輸入輸出格式</li></ul></li><li><p><strong><a href="./stage-prd/">階段 2：PRD - 產生產品需求文件</a></strong></p><ul><li>產生 MVP 級 PRD，包含使用者故事、功能清單和非目標</li><li>掌握需求分解和優先級排序技巧</li></ul></li><li><p><strong><a href="./stage-ui/">階段 3：UI - 設計介面與原型</a></strong></p><ul><li>使用 ui-ux-pro-max 技能設計 UI 結構和可預覽原型</li><li>理解介面設計流程和最佳實踐</li></ul></li><li><p><strong><a href="./stage-tech/">階段 4：Tech - 設計技術架構</a></strong></p><ul><li>設計最小可行的技術架構和 Prisma 資料模型</li><li>掌握技術選型和架構設計原則</li></ul></li><li><p><strong><a href="./stage-code/">階段 5：Code - 產生可執行程式碼</a></strong></p><ul><li>根據 UI Schema 和 Tech 設計產生前後端程式碼、測試和配置</li><li>理解程式碼產生流程和模板系統</li></ul></li><li><p><strong><a href="./stage-validation/">階段 6：Validation - 驗證程式碼品質</a></strong></p><ul><li>驗證依賴安裝、型別檢查、Prisma schema 和程式碼品質</li><li>掌握自動化品質檢查流程</li></ul></li><li><p><strong><a href="./stage-preview/">階段 7：Preview - 產生部署指南</a></strong></p><ul><li>產生完整的執行說明文件和部署配置</li><li>學習 CI/CD 整合和 Git Hooks 配置</li></ul></li></ul><h3 id="內部機制" tabindex="-1">內部機制 <a class="header-anchor" href="#內部機制" aria-label="Permalink to &quot;內部機制&quot;">​</a></h3><ul><li><p><strong><a href="./orchestrator/">Sisyphus 調度器詳解</a></strong></p><ul><li>理解調度器如何協調流水線、管理狀態和執行權限檢查</li><li>掌握調度策略和狀態機原理</li></ul></li><li><p><strong><a href="./context-optimization/">上下文優化：分會話執行</a></strong></p><ul><li>學習如何使用 <code>factory continue</code> 指令節省 Token</li><li>掌握在每個階段新建會話的最佳實踐</li></ul></li><li><p><strong><a href="./security-permissions/">權限與安全機制</a></strong></p><ul><li>理解能力邊界矩陣、越權處理和安全檢查機制</li><li>掌握安全配置和權限管理</li></ul></li><li><p><strong><a href="./failure-handling/">失敗處理與回滾</a></strong></p><ul><li>學習失敗識別、重試機制、回滾策略和人工介入流程</li><li>掌握故障排查和恢復技巧</li></ul></li></ul><h2 id="學習路徑建議" tabindex="-1">學習路徑建議 <a class="header-anchor" href="#學習路徑建議" aria-label="Permalink to &quot;學習路徑建議&quot;">​</a></h2><h3 id="推薦學習順序" tabindex="-1">推薦學習順序 <a class="header-anchor" href="#推薦學習順序" aria-label="Permalink to &quot;推薦學習順序&quot;">​</a></h3><ol><li><p><strong>先學完 7 階段流水線</strong>（按順序）</p><ul><li>Bootstrap → PRD → UI → Tech → Code → Validation → Preview</li><li>每個階段都有明確的輸入輸出，按順序學習能建立完整的認知</li></ul></li><li><p><strong>再學習調度器和上下文優化</strong></p><ul><li>理解 Sisyphus 如何協調這 7 個階段</li><li>學習如何優化上下文以節省 Token 成本</li></ul></li><li><p><strong>最後學習安全與失敗處理</strong></p><ul><li>掌握權限邊界和安全機制</li><li>了解失敗場景和應對策略</li></ul></li></ol><h3 id="不同角色的學習重點" tabindex="-1">不同角色的學習重點 <a class="header-anchor" href="#不同角色的學習重點" aria-label="Permalink to &quot;不同角色的學習重點&quot;">​</a></h3><table tabindex="0"><thead><tr><th>角色</th><th>重點學習章節</th></tr></thead><tbody><tr><td><strong>開發者</strong></td><td>Code、Validation、Tech、Orchestrator</td></tr><tr><td><strong>產品經理</strong></td><td>Bootstrap、PRD、UI、Preview</td></tr><tr><td><strong>技術負責人</strong></td><td>Tech、Code、Security、Failure Handling</td></tr><tr><td><strong>DevOps 工程師</strong></td><td>Validation、Preview、Context Optimization</td></tr></tbody></table><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>完成本章節後，你可以繼續學習：</p><ul><li><strong><a href="./../../faq/troubleshooting/">常見問題與故障排除</a></strong> - 解決實際使用中的問題</li><li><strong><a href="./../../faq/best-practices/">最佳實踐</a></strong> - 掌握高效使用 Factory 的技巧</li><li><strong><a href="./../../appendix/cli-commands/">CLI 指令參考</a></strong> - 查看完整的指令清單</li><li><strong><a href="./../../appendix/code-standards/">程式碼規範</a></strong> - 了解產生的程式碼應遵循的規範</li></ul><hr><p>💡 <strong>提示</strong>：如果在使用過程中遇到問題，請先查看 <a href="./../../faq/troubleshooting/">常見問題與故障排除</a> 章節。</p>',19)])])}const g=a(e,[["render",o]]);export{c as __pageData,g as default};
